{
  "verses": [
    {
      "n": 25,
      "column": "left",
      "text": "Jo es weddischn pahr\njums to Atreebfchanas-Sohbinu/\ntas tahs Derribaslabbad atreebē/\nun jepfchu juhs juhsōs Pilsfah-\ntōs fapulzesfeetees/ tottehr fuhti-\ntchu es to Mehri starp jums/ un\njuhs tapfeet ta Eenaidneeka Roh-\nkā nodohti.\n"
    },
    {
      "n": 26,
      "column": "left",
      "text": "Rad es jums to Maises\nPadohmu atxeinischu/ tad buhs\ndefmits Seewahm jawu Maisi\nweenâ Zepli zept/ un juhsu Mai-\nst ar Swarru atdoht / un juhs\nehdiſeet un ne pre-ehdifeet.\n"
    },
    {
      "n": 27,
      "column": "left",
      "text": "Un ja juhs zaar to arri-\ndsan mann ne klausifeet/ bet man\nprettiturefeetees.\n"
    },
    {
      "n": 28,
      "column": "left",
      "text": "Tad ir es jums eeksch\nBahrsibas prettiturreſchohs / un\npahrmahzischu juhs wehl feptin-\nkaht wairak juhsu Grehku deht.\n"
    },
    {
      "n": 29,
      "column": "left",
      "text": "Jo juhs ehdiſeet juhsu\nDehlu Meeju / un juhsu Meitu\nMeeju ehdiſeet juhs.\n"
    },
    {
      "n": 30,
      "column": "left",
      "text": "Un es iṣkaisischu juhsu\nKalnu Weetas/ un isdeldefchu\njuhsas Bildes/ un mettischu juh-\nfu Maitas us juhsu Subdu Elku\nMaitahm/ un manna Dwehfele\njuhsu apnifs.\n"
    },
    {
      "n": 31,
      "column": "left",
      "text": "Un es darrischu juhsas\nPilsfahtus pohstā/ un ispohti-\nschu juhsas fweltas Weetas/ un\nes ne gribbu juhsu faldu Sinar-\nschu obschnaht.\n"
    },
    {
      "n": 32,
      "column": "left",
      "text": "Es gribbu ta to Semmi\nispohtiht/ ka juhfeem Eenaidnee-\nkeem/ kas eeksch tahs dshwo/\nbuhs istrubzinatees.\n"
    },
    {
      "n": 33,
      "column": "left",
      "text": "Un es iṣkaisischu juhs starp\n"
    },
    {
      "n": 25,
      "column": "right",
      "text": "teem Paganeem/ un iswilkchu\npakat jums to Sohbinu / un\njuhsu Semme taps pohstā / un\njuhsu Pilsfahti taps ispohtiiti.\n"
    },
    {
      "n": 34,
      "column": "right",
      "text": "Tad tai Semmei jawu\nDuffschana patifs/ kainehr ta\npohstā irr/ un juhs Eenaidneeku\nSemmē effat/ tad dusfehs ta\nSemme/ un winnas Duffscha-\nna tai Semmei patifs.\n"
    },
    {
      "n": 35,
      "column": "right",
      "text": "Wiṣās jawas Pohsfischcha-\nnas Deenās dusfehs winna/ ta-\npehz ka ta ne dusfeja juhsas Dus-\nfeschanas-Deenās/ kad juhs eeksch\ntahs dshwojat.\n"
    },
    {
      "n": 36,
      "column": "right",
      "text": "Un teem Atlitkuscheem\njuhsu Starpā dobschu es bailu\nSirdi winnu Eenaidneeku Sem-\nmē/ ka weenas Lappas Tschak-\nstefchana / kas schaubahs / tohs\ndsīhs/ un tee behgs itt ka no Soh-\nbina/ un krittihś / fur tatschu ne\nweens pakkatdsihfees.\n"
    },
    {
      "n": 37,
      "column": "right",
      "text": "Un tee dausifees weens us\nohtrn/ itt ka no Sohbinā / fur\ntomehr ne weens pakkatdsihfees/\nun juhs ne stahweseet pretti\npreeksch juhsu Eenaidneeku Azsim.\n"
    },
    {
      "n": 38,
      "column": "right",
      "text": "Bet juhssefeet bohja starp\nteem Paganeem / un juhsu Ee-\nnaidneeku Semme juhs norihs.\n"
    },
    {
      "n": 39,
      "column": "right",
      "text": "Un tee Atlitkuschi juhsu\nStarpā panthks winnu Grehku\ndeht juhsu Eenaidneeku Semmē/\ntur buhs teem jawu Tehwu No-\nseegumo deht panikht.\n"
    },
    {
      "n": 40,
      "column": "right",
      "text": "Tad atsihs tee jawus No-\nseegumus/ un jawo Tehwo No-\nseegumu/ ar jawahn Pahrkahp-\nschanahm / ar ko tee prett mann\n"
    }
  ],
  "confidence": "high",
